// Transform Google Maps results into ChefFlow prospect format
const results = $input.all();
const prospects = [];

for (const item of results) {
  const place = item.json;
  if (!place.name) continue;

  // Map Google Maps category to ChefFlow category
  const types = (place.types || []).join(' ').toLowerCase();
  let category = 'other';
  if (types.includes('wedding') || types.includes('banquet')) category = 'wedding_planner';
  else if (types.includes('hotel') || types.includes('resort')) category = 'luxury_hotel';
  else if (types.includes('country_club') || types.includes('golf')) category = 'country_club';
  else if (types.includes('yacht') || types.includes('marina')) category = 'yacht_club';
  else if (types.includes('event') || types.includes('conference')) category = 'corporate_events';

  prospects.push({
    name: place.name,
    address: place.formatted_address || place.vicinity || null,
    city: null, // Parsed from address in enrichment
    state: null,
    category: category,
    latitude: place.geometry?.location?.lat || null,
    longitude: place.geometry?.location?.lng || null,
    description: place.editorial_summary?.overview || null,
    tags: ['google-maps-scrape'],
    priority: (place.rating >= 4.5 && place.user_ratings_total >= 100) ? 'high' : 'normal',
  });
}

return [{ json: { prospects } }];

// Filter out duplicates
const prospects = $node.transform.json.prospects;
const dedupResults = $node.dedup_check.json.results || [];

const newProspects = prospects.filter((p, i) => {
  const result = dedupResults[i];
  return result && !result.isDuplicate;
});

const skipped = prospects.length - newProspects.length;
console.log(`Dedup: ${newProspects.length} new, ${skipped} duplicates skipped`);

return [{ json: { prospects: newProspects, total: prospects.length, new_count: newProspects.length, skipped } }];
